fr:resource.fr:resource-source:
\AxiomC{\ensuremath{A\vphantom{|}}}
\AxiomC{\ensuremath{B\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  I:\quad }}
\BinaryInfC{\ensuremath{A \land  B\vphantom{|}}}
\DP
\hskip 1cm
\AxiomC{\ensuremath{A \land  B\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_l:\quad }}
\UnaryInfC{\ensuremath{A\vphantom{|}}}
\DP
\hskip 1cm
\AxiomC{\ensuremath{A \land  B\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_r:\quad }}
\UnaryInfC{\ensuremath{B\vphantom{|}}}
\DP


\AxiomC{\ensuremath{p \land  (q \rightarrow  r)\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_l:\quad }}
\UnaryInfC{\ensuremath{p\vphantom{|}}}
\AxiomC{\ensuremath{(p \lor  q) \land  (r \rightarrow  \neg  r)\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_r:\quad }}
\UnaryInfC{\ensuremath{r \rightarrow  \neg  r\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  I:\quad }}
\BinaryInfC{\ensuremath{p \land  (r \rightarrow  \neg  r)\vphantom{|}}}
\DP

\AxiomC{\ensuremath{A\vphantom{|}}}
\AxiomC{\ensuremath{B\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  I:\quad }}
\BinaryInfC{\ensuremath{A \land  B\vphantom{|}}}
\DP
\hskip 1cm
\AxiomC{\ensuremath{A \land  B\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_l:\quad }}
\UnaryInfC{\ensuremath{A\vphantom{|}}}
\DP
\hskip 1cm
\AxiomC{\ensuremath{A \land  B\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_r:\quad }}
\UnaryInfC{\ensuremath{B\vphantom{|}}}
\DP


\AxiomC{\ensuremath{p \land  (q \rightarrow  r)\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_l:\quad }}
\UnaryInfC{\ensuremath{p\vphantom{|}}}
\AxiomC{\ensuremath{(p \lor  q) \land  (r \rightarrow  \neg  r)\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_r:\quad }}
\UnaryInfC{\ensuremath{r \rightarrow  \neg  r\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  I:\quad }}
\BinaryInfC{\ensuremath{p \land  (r \rightarrow  \neg  r)\vphantom{|}}}
\DP

    \AxiomC{\ensuremath{p \rightarrow  q\vphantom{|}}}
            \AxiomC{\ensuremath{s \land  (r \rightarrow  q)\vphantom{|}}}
            \LeftLabel{\ensuremath{\scriptsize  \land  E_r:\quad }}
        \UnaryInfC{\ensuremath{r \rightarrow  q\vphantom{|}}}
        \LeftLabel{\ensuremath{\scriptsize  \lor  I_l:\quad }}
    \UnaryInfC{\ensuremath{(r \rightarrow  q) \lor  t\vphantom{|}}}
    \LeftLabel{\ensuremath{\scriptsize  \land  I:\quad }}
\BinaryInfC{\ensuremath{(p \rightarrow  q) \land  ((r \rightarrow  q) \lor  t)\vphantom{|}}}    
\LeftLabel{\ensuremath{\scriptsize  \land  E_l:\quad }}
\UnaryInfC{\ensuremath{p \rightarrow  q\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \lor  I_r:\quad }}
\UnaryInfC{\ensuremath{(s \land  t) \lor  (p \rightarrow  q)\vphantom{|}}}
\DP

    \AxiomC{\ensuremath{q \land  (p \lor  (r \land  t))\vphantom{|}}}
    \LeftLabel{\ensuremath{\scriptsize  \land  E_r:\quad }}
\UnaryInfC{\ensuremath{p \lor  (r \land  t)\vphantom{|}}}
    \AxiomC{\ensuremath{[p]^1\vphantom{|}}}
    \LeftLabel{\ensuremath{\scriptsize  \lor  I_r:\quad }}
\UnaryInfC{\ensuremath{r \lor  p\vphantom{|}}}
    \AxiomC{\ensuremath{[r \land  t]^1\vphantom{|}}}
    \LeftLabel{\ensuremath{\scriptsize  \land  E_l:\quad }}
    \UnaryInfC{\ensuremath{r\vphantom {r \land  s}\vphantom{|}}}
    \LeftLabel{\ensuremath{\scriptsize  \lor  I_l:\quad }}
\UnaryInfC{\ensuremath{r \lor  p\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \lor  E^1:\quad }}
\TrinaryInfC{\ensuremath{r \lor  p\vphantom{|}}}
\DP

\AxiomC{\ensuremath{p\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \lor  I_r:\quad }}
\UnaryInfC{\ensuremath{r \lor  p\vphantom{|}}}
\DP
\hskip 2cm
\AxiomC{\ensuremath{r \land  t\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_l:\quad }}
\UnaryInfC{\ensuremath{r\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \lor  I_l:\quad }}
\UnaryInfC{\ensuremath{r \lor  p\vphantom{|}}}
\DP

\AxiomC{\ensuremath{(p \rightarrow  (q \land  t)) \land  p\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_l:\quad }}
\UnaryInfC{\ensuremath{p \rightarrow  (q \land  t)\vphantom{|}}}    
\AxiomC{\ensuremath{(p \rightarrow  (q \land  t)) \land  p\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_r:\quad }}
\UnaryInfC{\ensuremath{p\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \rightarrow  E:\quad }}
\BinaryInfC{\ensuremath{q \land  t\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_r:\quad }}
\UnaryInfC{\ensuremath{t\vphantom{|}}}
\DP

\AxiomC{\ensuremath{[\bot ]^1\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \bot  E:\quad }}
\UnaryInfC{\ensuremath{p \land  (q \lor  r)\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  E_r:\quad }}
\UnaryInfC{\ensuremath{q \lor  r\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \rightarrow  I^1:\quad }}
\UnaryInfC{\ensuremath{\bot  \rightarrow  (q \lor  r)\vphantom{|}}}
\DP

\AxiomC{\ensuremath{(q \land  r) \rightarrow  \bot \vphantom{|}}}
\AxiomC{\ensuremath{q\vphantom{|}}}
\AxiomC{\ensuremath{r\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \land  I:\quad }}
\BinaryInfC{\ensuremath{q \land  r\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \rightarrow  E:\quad }}
\BinaryInfC{\ensuremath{\bot \vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \bot  E:\quad }}
\UnaryInfC{\ensuremath{\bot \vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \bot  E:\quad }}
\UnaryInfC{\ensuremath{(s \rightarrow  t) \land  ((p \lor  \neg  q) \land  \neg  (r \rightarrow  s))\vphantom{|}}}
\DP

\AxiomC{\ensuremath{\top  \rightarrow  q\vphantom{|}}}
\AxiomC{\ensuremath{\vphantom{\top }\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \top  I:\quad }}
\UnaryInfC{\ensuremath{\top \vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \rightarrow  E:\quad }}
\BinaryInfC{\ensuremath{q\vphantom{q \lor  r}\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \lor  I_r:\quad }}
\UnaryInfC{\ensuremath{\bot  \lor  q\vphantom{|}}}
\DP

\AxiomC{\ensuremath{\neg  i\vphantom{|}}}
\AxiomC{\ensuremath{m \rightarrow  i\vphantom{|}}}
\AxiomC{\ensuremath{[m]^1\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \rightarrow  E:\quad }}
\BinaryInfC{\ensuremath{i\vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \neg  E:\quad }}
\BinaryInfC{\ensuremath{\bot \vphantom{|}}}
\LeftLabel{\ensuremath{\scriptsize  \neg  I^1:\quad }}
\UnaryInfC{\ensuremath{\neg  m\vphantom{|}}}
\DP
